import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"45. Rosters","description":"","frontmatter":{"title":"45. Rosters","eba":"Nurses and Midwives 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/45-rosters.md","filePath":"ebas/nurses-midwives/hours-of-work/45-rosters.md"}'),a={name:"ebas/nurses-midwives/hours-of-work/45-rosters.md"};function n(i,e,l,p,h,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_45-rosters" tabindex="-1">45. Rosters <a class="header-anchor" href="#_45-rosters" aria-label="Permalink to &quot;45. Rosters&quot;">​</a></h1><p>This clause does not apply to casual Employees, DONs or Deputy DONs.</p><p><strong>45.1</strong> Subject to clause 45.10, the ordinary hours of full-time and part-time Employees will be worked according to a written roster that will:</p><p><strong>(a)</strong> be of at least 28 days duration;</p><p><strong>(b)</strong> be posted at least 28 days before it comes into operation in each work location where it can be readily seen by Employees and representatives of the Employees, including the Unions, without notice; and</p><p><strong>(c)</strong> as far as is practicable reflect the roster each Employee will work.</p><p>Nothing in this clause precludes an Employer from also issuing the roster or the on-call roster in electronic form.</p><p><strong>45.2</strong> Rosters will:</p><p><strong>(a)</strong> set out:</p><p><strong>(i)</strong> the Employees&#39; daily ordinary working hours;</p><p><strong>(ii)</strong> starting and finishing times; and</p><p><strong>(iii)</strong> meal intervals;</p><p><strong>(b)</strong> have a staffing and skill mix that complies with the Safe Patient Care Act if applicable to that ward or unit;</p><p><strong>(c)</strong> allocate a Registered Nurse/Registered Midwife to be in charge of each shift;</p><p><strong>(d)</strong> not change without at least fourteen days&#39; notice of a change in roster other than in an emergency situation external to the Employer, subject to 45.8 below;</p><p><strong>(e)</strong> provide an Employee who works 0.8 EFT or more with two consecutive days off per week. Nothing in this subclause (e) is intended to:</p><p><strong>(i)</strong> restrict an Employee requesting single days off, including as a self rostering request; or</p><p><strong>(ii)</strong> prevent an Employee who works 0.8 EFT or more from having a single day off rostered where they also have consecutive days off rostered that week.</p><p>See <a href="/eba/ebas/nurses-midwives/hours-of-work/44-breaks.html">clause 44</a> for further information on the requirement for an Employer to have a system that records meal breaks.</p><p><strong>45.3</strong> Roster not posted at least 28 days before it comes into operation</p><p><strong>(a)</strong> From 8 July 2024, where a roster is not posted 28 days in advance as required by clause 45.1, each shift in the roster that is worked with less than 28 days&#39; notice shall attract a change of roster allowance as prescribed at subclause 45.8(ii).</p><p>Example: A roster for a ward was posted 25 days before coming into effect, rather than 28 days as required by clause 45.1. A change of roster is payable for those shifts worked on the roster with less than 28 days&#39; notice.</p><p><strong>(b)</strong> The provisions of subclause 45.3(a) do not apply where:</p><p><strong>(i)</strong> In respect of a shift that the Employee agrees to work as an additional shift under the supplementary roster;</p><p><strong>(ii)</strong> In respect of a shift that the Employee works that already attracts the Change of Roster allowance under clause 45.8;</p><p><strong>(iii)</strong> The shift was not rostered in advance because the Employee swapped shifts by agreement with another Employee; or</p><p><strong>(iv)</strong> The roster is varied in accordance with this Agreement, for example clauses 45.5 or 45.8.</p><p><strong>45.4</strong> Breaks between Rostered Shifts</p><p>The roster or rosters will be drawn up so as to provide at least eight hours between successive ordinary shifts.</p><p><strong>45.5</strong> Fixed Rosters</p><p><strong>(a)</strong> An Employee, by making a written request to the Employer, may have a roster fixed by mutual agreement (subject to the other provisions of this Agreement) in lieu of the provisions of clauses 45.1 to 45.2 save that:</p><p><strong>(i)</strong> an Employer will not unreasonably refuse a request for a fixed roster agreement where the Employee can demonstrate a regular and systematic pattern of work (as defined below);</p><p><strong>(A)</strong> regular and systematic pattern of work means working set days or shifts in a demonstrable pattern over the preceding six months (recognising that additional ordinary shifts may be worked around that fixed pattern); but</p><p><strong>(B)</strong> does not include shifts worked because the Employee who usually works them is on extended leave;</p><p><strong>(ii)</strong> where a fixed roster agreement is made, the Employer will provide the Employee with an amended Letter of Appointment detailing the fixed roster agreement which will be consistent with the regular and systematic pattern of work described at (A) and (B) above; and</p><p><strong>(iii)</strong> where the Employer proposes to change the Employee&#39;s fixed roster agreement, the terms of <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> (Consultation) or <a href="/eba/ebas/nurses-midwives/consultation-disputes/11A-consultation-about-changes-to-rosters-or-hours-of-work.html">clause 11A</a> (Consultation about changes to rosters or hours of work) will apply, depending on the circumstances.</p><p><strong>(b)</strong> A written request for a fixed roster may be made in circumstances where the Employer is proposing to alter, or has recently altered, the Employee’s regular and systematic pattern of work.</p><p><strong>(c)</strong> An Employee may end the fixed roster agreement at any time by giving written notice to the Employer. In such a case, the roster for the Employee will be set according to the provisions of clauses 45.1 to 45.2 above from the commencement of the next full roster period being not less than five clear days after the written notice is received.</p><p><strong>45.6</strong> Replacing unplanned absences</p><p><strong>(a)</strong> Reasonable effort to replace with permanent Employee</p><p><strong>(i)</strong> In the event a vacancy occurs on the roster arising from an unplanned absence of the rostered Employee, a reasonable effort must be made to fill the vacancy with a permanent Employee working no less than the same shift length as was rostered.</p><p><strong>(ii)</strong> In this clause, a reasonable effort means:</p><p><strong>(A)</strong> contacting nurses/midwives who are available including in accordance with the supplementary roster;</p><p><strong>(B)</strong> if the shift is not filled, reasonable attempts to ask nurses/midwives on that ward/unit to fill the vacancy (except where it would result in overtime); and</p><p><strong>(C)</strong> if the shift is not filled, seeking to allocate a Pool Employee.</p><p><strong>(iii)</strong> The Employer will document its attempts to replace the vacancy which must be available for inspection by the Union and local Union representatives upon request.</p><p><strong>(b)</strong> Use of bank or agency staff</p><p>Where, after a reasonable effort, the Employer cannot obtain a permanent Employee, the rostered shift can only be replaced by anything other than the full shift length in accordance with <a href="/eba/ebas/nurses-midwives/hours-of-work/47-avoidance-and-management-of-short-shifts.html">clause 47</a> (Avoidance and Management of Short Shifts).</p><p><strong>45.7</strong> On-Call Rosters</p><p>The intent of this clause is to ensure Employees have a reasonably predictable pattern of work during the on-call roster period. This clause does not apply to casual Employees, DONs or Deputy DONs.</p><p><strong>(a)</strong> Planned on-call arrangement means the on-call arrangements the Employer would reasonably expect to be required within the work location at the time the on-call roster is released.</p><p><strong>(b)</strong> Planned on-call arrangements for full-time and part-time Employees will be:</p><p><strong>(i)</strong> worked according to a written roster of at least 28 days duration; and</p><p><strong>(ii)</strong> posted at least 28 days before it comes into operation in each work location where it can be readily seen by Employees and representatives of the Employees, including the Union, without notice.</p><p><strong>(c)</strong> Nothing in this clause prevents an Employer placing an Employee on call in circumstances where the requirement for the Employee to be rostered on call was not known at the time the roster was released, save that where this occurs, the allowance at clause 45.8 applies.</p><p><strong>(d)</strong> On-call/recall payments are located at <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>.</p><p><strong>45.8</strong> Change of Roster Allowance</p><p><strong>(a)</strong> If the Employer changes an Employee&#39;s roster or planned on call roster once set in accordance with clauses 45.1 or 45.7, other than as excepted in subclause 45.2(d), the Change of Roster Allowance will apply in relation to each change as follows:</p><p><strong>(i)</strong> 7 days&#39; or less notice, the applicable rate in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2; and</p><p><strong>(ii)</strong> 8 to 14 days&#39; notice, the applicable rate in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2.</p><p>This allowance is not payable to a part-time Employee for an additional shift worked unless the circumstances described in <a href="/eba/ebas/nurses-midwives/hours-of-work/46-supplementary-roster-and-additional-shifts.html">clause 46.4</a> (Supplementary Roster and Additional Shifts) apply.</p><p><strong>(b)</strong> If an additional shift is worked by a part-time Employee other than under the supplementary roster, it attracts the Change of Roster Allowance as described at subclause 45.8(a)(ii) above.</p><p><strong>(c)</strong> This clause 45.8 does not apply to those circumstances covered by <a href="/eba/ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.html">clause 41A</a> (Change of Ward Allowance) unless the start and/or finish time on the Employee’s roster, in relation to ordinary hours, also change.</p><p><strong>45.9</strong> Rosters which include work on public holidays</p><p><strong>(a)</strong> Employers must implement a policy or procedure for the issuance and finalisation of rosters which cover the performance of work on a public holiday under the Act.</p><p><strong>(b)</strong> The policy / procedure referenced at subclause 45.9(a) above should:</p><p><strong>(i)</strong> set out the process for an Employee to request not to work on a public holiday they are requested to work; and</p><p><strong>(ii)</strong> set out the process for the Employer to provide a written response to an Employee&#39;s request not to work on a public holiday they are requested to work.</p><p><strong>(c)</strong> An Employer who receives a request under subclause 45.9(b)(i) must accept that request unless the Employer determines that the refusal is not reasonable in the circumstances. The factors an Employer must consider when determining whether a request is not reasonable include:</p><p><strong>(i)</strong> whether the Employee has clearly explained a reason for refusing to work on the relevant public holiday;</p><p><strong>(ii)</strong> the nature of the Employers’ workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee;</p><p><strong>(iii)</strong> the capacity for the Employer to find a replacement Employee to perform the same work;</p><p><strong>(iv)</strong> the Employee’s personal circumstances (including family responsibilities) to the extent that those circumstances have been disclosed to the Employer;</p><p><strong>(v)</strong> whether the Employee could reasonably have expected the Employer to request that they work on the public holiday(s);</p><p><strong>(vi)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects expectation of, work on the public holiday(s);</p><p><strong>(vii)</strong> the type of employment of the Employee (e.g., whether full-time, part- time, casual or shiftwork);</p><p><strong>(viii)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request;</p><p><strong>(ix)</strong> the amount of notice in advance of the public holiday given by the Employee when refusing the request;</p><p><strong>(x)</strong> the number of public holidays the Employee has previously worked and been required to work in recent roster durations; and</p><p><strong>(xi)</strong> any other relevant matter.</p><p><strong>(d)</strong> Where the Employer has requested an Employee to work any public holiday(s) and either:</p><p><strong>(i)</strong> the Employee has not made a request not to work the public holiday in accordance with the policy or procedure referenced at subclause 45.9(a) above; or</p><p><strong>(ii)</strong> the Employer has determined that a request was not reasonable (taking into account the factors in subclause 45.9(c)),</p><p>the Employer may require the Employee to work on the relevant public holiday(s).</p><p><strong>45.10</strong> Employees not required to have a roster</p><p><strong>(a)</strong> The requirement to have a roster at clause 45.1 and payments for failing to post a roster at clause 45.3 do not apply to those Employees who are genuinely not required to work in accordance with a roster. Whether an Employee is genuinely not required to work in accordance with a roster shall be determined on the circumstances including:</p><p><strong>(i)</strong> The nature of the role and the environment in which it operates;</p><p><strong>(ii)</strong> The practice at the worksite; and/or</p><p><strong>(iii)</strong> That the Employee’s work hours are set or self-directed.</p><p><strong>(b)</strong> This clause 45.10 does not limit an Employer’s obligations in respect to on-call rosters.</p><p><strong>(c)</strong> By not later than 1 November 2024 the Employer will provide the WIC with a list of existing Employee positions it says do not work in accordance with a roster. Any disputes about whether such Employees are genuinely not required to work</p><p>in accordance with a roster (for the purposes of subclause (a) above) that are not resolved at the WIC will be referred to the Central Implementation Committee.</p><p><strong>(d)</strong> Where the Employer is proposing to create a position to which this clause 45.10 applies, this information will be included in the change impact statement required under <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a> (Consultation).</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',94)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
